/*******
 * Gets the days between inception and expiration date
 * By Adriana Centellas
*******/ 

// Data type Date
const dateA = new Date(this.CQP_INCEPTION_DATE);
const dateB = new Date(this.CQP_EXPIRATION_DATE);

// Calculate difference un miliseconds
const diffTime = dateB - dateA;

// To days
const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

return diffDays;

/*******
 * Gets the months between inception and expiration date
 * By Adriana Centellas
*******/ 

const dateA = new Date(this.CQP_INCEPTION_DATE);
const dateB = new Date(this.CQP_EXPIRATION_DATE);

let months =
  (dateB.getFullYear() - dateA.getFullYear()) * 12 +
  (dateB.getMonth() - dateA.getMonth());

//In case expiration date is before inception date
if (dateB.getDate() < dateA.getDate()) {
  months--;
}

return months;

/*******
 * Gets the expiration adding the months selected on dropdown
 * By Adriana Centellas
***/

function addMonthsSafe(dateStr, monthsToAdd) {
  // Parse input
  const [yStr, mStr, dStr] = dateStr.split("-");
  let year = parseInt(yStr, 10);
  let month = parseInt(mStr, 10); // 1–12
  const day = parseInt(dStr, 10);
  const months = parseInt(monthsToAdd, 10);

  // Add the months directly
  month += months;

  // Adjust for overflow (more than 12 months)
  while (month > 12) {
    month -= 12;
    year++;
  }

  // Adjust for underflow (negative months)
  while (month < 1) {
    month += 12;
    year--;
  }

  // Determine how many days exist in the new target month
  const daysInTargetMonth = new Date(year, month, 0).getDate();

  // Clamp the day if it doesn't exist in the target month
  const newDay = Math.min(day, daysInTargetMonth);

  // Format to yyyy-mm-dd
  const formatted = `${year}-${String(month).padStart(2, "0")}-${String(newDay).padStart(2, "0")}`;

  return formatted;
}

return addMonthsSafe(this.CQP_INCEPTION_DATE, this.CQP_ADD_INCEPTION_DATE);

/*****
 * To populate variable in case normal or special expiration date
 * 
 * By Adriana Centellas
 */

if (this.CQP_SPECIAL_CASE) {
    return this.CQP_ADD_INCEPTION_DATE_SPECIAL;
} else {
    return this.CQP_ADD_INCEPTION_DATE_NORMAL;
}

/****
 * Return the Risk by Country selected
 * By Adriana Centellas
 */

return this.CQP_COUNTRY.RISK;

/*
* This function calculates de Underwriting year based on the date selected on the Inception Date field,
* it sets the threshold (from July to June) based on the selected date and compares the date to the threshold,
* if it falls in the threshold returns the current year, otherwise it returns the previous year
*
* by Mateo Rada Arias
*/
const inceptionDateStr = this.CQP_INCEPTION_DATE; // Get data from Inception Date dropwdown as a string

// Check if the date hasn't been selected yet
if(inceptionDateStr == null){
    return "";
}

let inceptionDate = new Date(inceptionDateStr); // Create a Date object with the date string
const currentYear = inceptionDate.getFullYear(); // Get current date's year

// Define July 1st of the current year and June 30th of the next year
const julyStart = new Date(currentYear, 6, 1); // Month is 0-indexed: 6 = July
const juneEnd = new Date(currentYear + 1, 5, 30); // 5 = June

// Check if inception date is between July of current year and June of next year
if (inceptionDate >= julyStart && inceptionDate <= juneEnd) {
    return currentYear;
} else {
    return currentYear - 1;
}

/*******
 * Filter CQP_COMMODITIES by CQP_COMMODITIES_PROFILE
 * Returns all entries (CARGO / STORAGE) whose COMMODITY matches
 * the selected profile (e.g. "AGRICULTURAL PRODUCTS").
 *
 * @param none
 * @return (Array) filtered commodities for the selected profile
 *
 * by Adriana Centellas
 *******/

// 1) Get full commodities array (fallback to empty array if null/undefined)
var allCommodities = this.CQP_COMMODITIES || [];

// 2) Get selected commodity profile (expected to be a plain string)
var selectedCommodity = (this.CQP_COMMODITIES_PROFILE || '')
  .toString()
  .trim()
  .toUpperCase();


// If nothing is selected, return empty array
if (!selectedCommodity) {
  return [];
}


// 3) Filter by COMMODITY name (case-insensitive)
var filteredCommodities = allCommodities.filter(function (item) {
  // Guard clause in case item or COMMODITY is missing
  if (!item || !item.COMMODITY) {
    return false;
  }

  var itemCommodity = item.COMMODITY.toString().trim().toUpperCase();
  return itemCommodity === selectedCommodity;
});


// 4) Return all matches for that COMMODITY
return filteredCommodities;

/*****
 * Validation with conditional logic
 * By Adriana Centellas
 */

const fields = [
  { name: "Type", value: this.CQP_TYPE },
  { name: "Country", value: this.CQP_COUNTRY },
  { name: "Currency", value: this.CQP_CURRENCY },
  { name: "Reinsurance Broker", value: this.CQP_REINSURANCE_BROKER },
  { name: "Inception Date", value: this.CQP_INCEPTION_DATE },
  { name: "Interest", value: this.CQP_INTEREST },
  { name: "Commodities Profile", value: this.CQP_COMMODITIES_PROFILE }
];

let isValid = true;
let missingFields = [];

// -------------------------
// Normal validations
// -------------------------
fields.forEach(function (f) {
  if (f.value === null || f.value === undefined || f.value === "") {
    isValid = false;
    missingFields.push(f.name);
  }
});

// -------------------------
// Inception date logic (OR)
// -------------------------
if (
  (!this.CQP_ADD_INCEPTION_DATE_NORMAL || this.CQP_ADD_INCEPTION_DATE_NORMAL === "") &&
  (!this.CQP_ADD_INCEPTION_DATE_SPECIAL || this.CQP_ADD_INCEPTION_DATE_SPECIAL === "")
) {
  isValid = false;
  missingFields.push("Months add to inception date");
}

// -------------------------
// Special case validation
// -------------------------
if (this.CQP_SPECIAL_CASE === true) {
  if (
    this.CQP_SPECIAL_CASE_REASON === null ||
    this.CQP_SPECIAL_CASE_REASON === undefined ||
    this.CQP_SPECIAL_CASE_REASON === ""
  ) {
    isValid = false;
    missingFields.push("Special Case Reason");
  }
}

// -------------------------
// Return
// -------------------------
return {
  isValid: isValid,
  message: isValid ? "" : "Missing or invalid fields: " + missingFields.join(", ")
};
